const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const trigger = $('workflow_trigger').first().json;
const contentType = trigger.content_type || '';
const rawSearch = trigger.search_term || '';
const rawLower = rawSearch.toLowerCase();
const httpSelf = this;

// Special operation: list_story_arcs
if (contentType === 'story_arc' || rawLower.indexOf('story arc') >= 0 || rawLower.indexOf('story arcs') >= 0 || trigger.operation === 'list_story_arcs') {
  const resp = await httpSelf.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/story_arcs?order=name.asc&select=id,name,description',
    headers
  });
  const arcs = Array.isArray(resp) ? resp : [];
  if (arcs.length === 0) {
    return [{ json: { found: false, result: 'No story arcs found. Add arcs to the story_arcs table.', content_type: 'story_arc_list', title: '', content_text: '', content_id: '' } }];
  }
  const list = arcs.map((a, i) => (i + 1) + '. **' + a.name + '** — ' + a.description).join('\n');
  return [{ json: { found: true, result: 'Available story arcs:\n' + list, content_type: 'story_arc_list', title: 'Story Arcs', content_text: list, content_id: '' } }];
}

// Special operation: list_projects
if (trigger.operation === 'list_projects' || rawLower.trim() === 'list_projects') {
  const resp = await httpSelf.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects?order=created_at.desc&select=id,title,genre_slug,created_at',
    headers
  });
  const projects = Array.isArray(resp) ? resp : [];
  if (projects.length === 0) {
    return [{ json: { found: false, result: 'No writing projects found. Start by brainstorming a story.', content_type: 'project_list', title: '', content_text: '', content_id: '' } }];
  }
  const list = projects.map((p, i) => (i + 1) + '. ' + p.title + ' (' + (p.genre_slug || 'no genre') + ') — created ' + new Date(p.created_at).toLocaleDateString()).join('\n');
  return [{ json: { found: true, result: 'Found ' + projects.length + ' writing project(s):\n' + list, content_type: 'project_list', title: 'Writing Projects', content_text: list, content_id: '' } }];
}

// Special operation: list_outlines — triggered by "list outlines", "show outlines", "all outlines", or content_type=outline with no specific title
const isListOutlines = trigger.operation === 'list_outlines' || /\b(list|show|all)\b.*\boutline/i.test(rawSearch) || (contentType === 'outline' && /\b(list|show|all)\b/i.test(rawSearch));
if (isListOutlines) {
  const resp = await httpSelf.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects?outline=not.is.null&order=updated_at.desc&select=id,title,genre_slug,status,chapter_count,outline,updated_at',
    headers
  });
  const projects = Array.isArray(resp) ? resp : [];
  const withOutlines = projects.filter(function(p) { return p.title && p.outline && typeof p.outline === 'object' && Object.keys(p.outline).length > 0; });
  if (withOutlines.length === 0) {
    return [{ json: { found: false, result: 'No outlines found. Start by brainstorming a story.', content_type: 'outline_list', title: '', content_text: '', content_id: '' } }];
  }
  const list = withOutlines.map((p, i) => (i + 1) + '. **' + p.title + '** (' + (p.genre_slug || 'no genre') + ') — ' + (p.status || 'outlined') + ', ' + (p.chapter_count || 0) + ' chapters — updated ' + new Date(p.updated_at).toLocaleDateString()).join('\n');
  return [{ json: { found: true, result: 'Found ' + withOutlines.length + ' outline(s):\n' + list, content_type: 'outline_list', title: 'Story Outlines', content_text: list, content_id: '' } }];
}

// Special operation: outline_versions — list version history for a project
const isOutlineVersions = trigger.operation === 'outline_versions' || /\b(version|versions|history)\b.*\boutline/i.test(rawSearch) || /\boutline\b.*\b(version|versions|history)\b/i.test(rawSearch);
if (isOutlineVersions) {
  const vSearchTerms = rawLower.replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && ['the','outline','version','versions','history','show','list','for','get'].indexOf(w) === -1; }).slice(0, 4);
  let projectId = null;
  let projectTitle = '';
  for (const term of vSearchTerms) {
    const pResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title&limit=1', headers });
    if (Array.isArray(pResp) && pResp.length > 0) { projectId = pResp[0].id; projectTitle = pResp[0].title; break; }
  }
  if (!projectId) { return [{ json: { found: false, result: 'No project found matching: ' + rawSearch, content_type: 'outline_version_list', title: '', content_text: '', content_id: '' } }]; }
  const verResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/outline_versions?project_id=eq.' + projectId + '&order=version_number.desc&select=id,version_number,revision_note,created_at', headers });
  const versions = Array.isArray(verResp) ? verResp : [];
  if (versions.length === 0) { return [{ json: { found: true, result: 'No version history found for "' + projectTitle + '". Versions are saved automatically on each revision going forward.', content_type: 'outline_version_list', title: projectTitle, content_text: '', content_id: '' } }]; }
  const vList = versions.map(function(v, i) { return (i + 1) + '. Version ' + v.version_number + ' — ' + new Date(v.created_at).toLocaleString() + (v.revision_note ? ' (' + v.revision_note + ')' : ''); }).join('\n');
  return [{ json: { found: true, result: 'Outline versions for "' + projectTitle + '":\n' + vList + '\n\nTo revert: "revert outline for ' + projectTitle + ' to version N"', content_type: 'outline_version_list', title: projectTitle, content_text: vList, content_id: '' } }];
}

// Special operation: revert_outline — revert outline to a specific version
const revertMatch = rawLower.match(/revert.*outline.*(?:to|version)\s*(\d+)/i) || (trigger.operation === 'revert_outline' ? [null, trigger.version_number] : null);
if (revertMatch) {
  const targetVersion = parseInt(revertMatch[1]);
  const rSearchTerms = rawLower.replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && ['the','outline','version','revert','to','for','get','back'].indexOf(w) === -1 && !/^\d+$/.test(w); }).slice(0, 4);
  let rProjectId = null;
  let rProjectTitle = '';
  for (const term of rSearchTerms) {
    const pResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title&limit=1', headers });
    if (Array.isArray(pResp) && pResp.length > 0) { rProjectId = pResp[0].id; rProjectTitle = pResp[0].title; break; }
  }
  if (!rProjectId) { return [{ json: { found: false, result: 'No project found matching: ' + rawSearch, content_type: 'outline_revert', title: '', content_text: '', content_id: '' } }]; }
  const vResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/outline_versions?project_id=eq.' + rProjectId + '&version_number=eq.' + targetVersion + '&select=outline,version_number&limit=1', headers });
  if (!Array.isArray(vResp) || vResp.length === 0) { return [{ json: { found: false, result: 'Version ' + targetVersion + ' not found for "' + rProjectTitle + '". Use "outline version history for ' + rProjectTitle + '" to see available versions.', content_type: 'outline_revert', title: rProjectTitle, content_text: '', content_id: '' } }]; }
  const oldOutline = vResp[0].outline;
  await httpSelf.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/writing_projects?id=eq.' + rProjectId, headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' }, body: { outline: oldOutline, updated_at: new Date().toISOString() } });
  const chars = (oldOutline.characters || []).map(function(c) { return c.name; }).join(', ');
  return [{ json: { found: true, result: 'Reverted "' + rProjectTitle + '" to version ' + targetVersion + '. Characters: ' + chars + '. Chapters: ' + (oldOutline.chapters || []).length, content_type: 'outline_revert', title: rProjectTitle, content_text: 'Reverted to version ' + targetVersion, content_id: rProjectId } }];
}

const stopWords = ['the', 'a', 'an', 'in', 'on', 'at', 'to', 'for', 'of', 'and', 'or', 'is', 'are', 'was', 'were', 'how', 'what', 'why', 'when', 'my', 'draft', 'about', 'called', 'titled', 'named', 'get', 'pull', 'up', 'blog', 'post', 'story', 'short', 'newsletter', 'chapter', 'report', 'research', 'all', 'chapters', 'from', 'project', 'retrieve', 'fetch', 'find', 'outline', 'outlines', 'list', 'show'];
const words = rawSearch.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) {
  return w.length > 2 && stopWords.indexOf(w) === -1;
});
const searchTerms = words.slice(0, 4);

let title = '';
let contentText = '';
let storagePath = '';
let contentId = '';
let foundType = contentType;
async function searchProjectChapters(terms) {
  for (const term of terms) {
    const url = supabaseUrl + '/rest/v1/writing_projects?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title,genre_slug&limit=5';
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const projects = Array.isArray(resp) ? resp : [];
    if (projects.length > 0) {
      const project = projects[0];
      const chapUrl = supabaseUrl + '/rest/v1/published_content?project_id=eq.' + project.id + '&content_type=eq.chapter&order=chapter_number.asc&select=id,title,content_type,status,chapter_number,created_at';
      const chapResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: chapUrl, headers });
      const chapters = Array.isArray(chapResp) ? chapResp : [];
      return { project, chapters };
    }
  }
  return null;
}

async function searchPublishedContent(type, terms) {
  for (const term of terms) {
    let url = supabaseUrl + '/rest/v1/published_content?title=ilike.*' + encodeURIComponent(term) + '*&order=created_at.desc&limit=5';
    if (type) url += '&content_type=eq.' + type;
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length > 0) {
      const best = items.find(function(item) {
        const t = (item.title || '').toLowerCase();
        return terms.filter(function(kw) { return t.indexOf(kw) >= 0; }).length >= 2;
      }) || items[0];
      return best;
    }
  }
  return null;
}

async function searchResearchReports(terms) {
  for (const term of terms) {
    const url = supabaseUrl + '/rest/v1/research_reports?topic=ilike.*' + encodeURIComponent(term) + '*&order=updated_at.desc&limit=5';
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length > 0) {
      const best = items.find(function(item) {
        const t = (item.topic || '').toLowerCase();
        return terms.filter(function(kw) { return t.indexOf(kw) >= 0; }).length >= 2;
      }) || items[0];
      return best;
    }
  }
  return null;
}

try {
  // Outline search: if content_type is outline or search mentions outline, look in writing_projects
  if (contentType === 'outline' || contentType === '' || rawSearch.toLowerCase().indexOf('outline') >= 0) {
    for (const term of searchTerms) {
      const url = supabaseUrl + '/rest/v1/writing_projects?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title,genre_slug,outline,created_at&limit=5';
      const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
      const projects = Array.isArray(resp) ? resp : [];
      const match = projects.find(function(p) { return p.outline && Object.keys(p.outline).length > 0; });
      if (match) {
        const o = match.outline;
        const parts = [];
        parts.push('# Story Outline: ' + (o.title || match.title));
        if (o.premise) parts.push('\n## Premise\n' + o.premise);
        if (o.themes) parts.push('\n## Themes\n' + (Array.isArray(o.themes) ? o.themes.join(', ') : o.themes));
        if (o.characters) {
          parts.push('\n## Characters');
          o.characters.forEach(function(c) { parts.push('- **' + c.name + '** (' + c.role + '): ' + c.arc + (c.description ? ' \u2014 ' + c.description : '')); });
        }
        if (o.chapters) {
          parts.push('\n## Story Structure');
          o.chapters.forEach(function(ch) { parts.push((ch.number || '?') + '. **' + ch.title + '**: ' + ch.brief + (ch.arc_notes ? ' _[Arc: ' + ch.arc_notes + ']_' : '')); });
        }
        const outlineText = parts.join('\n');
        return [{ json: { found: true, title: o.title || match.title, content_text: outlineText, content_type: 'outline', content_id: match.id, result: 'Found outline: ' + (o.title || match.title) + ' (' + outlineText.length + ' chars)' } }];
      }
    }
    if (contentType === 'outline') {
      return [{ json: { found: false, result: 'No outline found for: ' + rawSearch + '. Try brainstorming a story first.', content_type: 'outline', title: '', content_text: '', content_id: '' } }];
    }
  }

  // Project-based chapter search: if content_type is chapter or unspecified, try to match a project first
  if (contentType === '' || contentType === 'chapter') {
    const projectResult = await searchProjectChapters(searchTerms);
    if (projectResult) {
      const { project, chapters } = projectResult;
      if (chapters.length === 0) {
        // Fallback: project_id may not be set on older chapters — search by genre_slug
        if (project.genre_slug) {
          const fallbackUrl = supabaseUrl + '/rest/v1/published_content?content_type=eq.chapter&genre_slug=eq.' + encodeURIComponent(project.genre_slug) + '&order=created_at.desc&limit=10&select=id,title,content_type,status,chapter_number,created_at';
          const fallbackResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: fallbackUrl, headers });
          const fallbackChapters = Array.isArray(fallbackResp) ? fallbackResp : [];
          if (fallbackChapters.length > 0) {
            const flist = fallbackChapters.map((c, i) =>
              (i + 1) + '. Chapter ' + (c.chapter_number || '?') + ': ' + (c.title || 'Untitled') + ' — ' + (c.status || 'draft') + ' [ID: ' + c.id + ']'
            ).join('\n');
            const fsummary = 'Project: ' + project.title + ' (' + project.genre_slug + ')\nFound ' + fallbackChapters.length + ' chapter(s):\n' + flist;
            return [{ json: { found: true, result: fsummary, content_type: 'chapter_list', title: project.title, content_text: fsummary, content_id: '' } }];
          }
        }
        return [{ json: { found: false, result: 'Project "' + project.title + '" found but no chapters written yet. Use Write Chapter to write the first chapter.', content_type: 'chapter_list', title: project.title, content_text: '', content_id: '' } }];
      }
      const list = chapters.map((c, i) =>
        (i + 1) + '. Chapter ' + (c.chapter_number || '?') + ': ' + (c.title || 'Untitled') + ' — ' + (c.status || 'draft') + ' [ID: ' + c.id + ']'
      ).join('\n');
      const summary = 'Project: ' + project.title + ' (' + (project.genre_slug || 'no genre') + ')\nFound ' + chapters.length + ' chapter(s):\n' + list;
      return [{ json: { found: true, result: summary, content_type: 'chapter_list', title: project.title, content_text: summary, content_id: '' } }];
    }
  }

  if (contentType === 'research_report') {
    const item = await searchResearchReports(searchTerms);
    if (item) {
      title = item.topic || 'Research Report';
      contentText = item.content || '';
      contentId = item.id;
    }
  } else if (['short_story', 'blog_post', 'newsletter', 'chapter'].indexOf(contentType) >= 0) {
    const item = await searchPublishedContent(contentType, searchTerms);
    if (item) {
      title = item.title || 'Untitled';
      contentText = item.content_text || '';
      storagePath = item.storage_path || '';
      contentId = item.id;
    }
  } else {
    var pcItem = await searchPublishedContent('', searchTerms);
    if (pcItem) {
      title = pcItem.title || 'Untitled';
      contentText = pcItem.content_text || '';
      storagePath = pcItem.storage_path || '';
      contentId = pcItem.id;
      foundType = pcItem.content_type || 'unknown';
    } else {
      var rrItem = await searchResearchReports(searchTerms);
      if (rrItem) {
        title = rrItem.topic || 'Research Report';
        contentText = rrItem.content || '';
        contentId = rrItem.id;
        foundType = 'research_report';
      }
    }
  }

  if (contentText === '' && storagePath) {
    const storageUrl = supabaseUrl + '/storage/v1/object/' + storagePath;
    const sHeaders = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };
    try {
      contentText = await httpSelf.helpers.httpRequest({ method: 'GET', url: storageUrl, headers: sHeaders, returnFullResponse: false });
      if (typeof contentText !== 'string') contentText = JSON.stringify(contentText);
    } catch (e) {
      contentText = '[Error fetching from storage: ' + e.message + ']';
    }
  }

  if (contentText === '' && title === '') {
    return [{ json: { found: false, result: 'No content found for: ' + rawSearch + ' (type: ' + (contentType || 'any') + '). Keywords: ' + searchTerms.join(', ') } }];
  }

  var maxLen = 100000;
  if (contentText.length > maxLen) {
    contentText = contentText.substring(0, maxLen) + ' [Truncated]';
  }

  return [{ json: { found: true, title: title, content_text: contentText, content_type: foundType, content_id: contentId, result: 'Found: ' + title + ' (' + foundType + ', ' + contentText.length + ' chars)' } }];
} catch (err) {
  return [{ json: { found: false, result: 'Error: ' + err.message } }];
}
